<!doctype html><html><head><meta charset="utf-8"><title>Payout <?= e((string)$batch['payout_reference']) ?></title><style>body{font-family:Arial,sans-serif;color:#111827;margin:32px}table{width:100%;border-collapse:collapse}th,td{padding:8px;border-bottom:1px solid #e5e7eb;text-align:left}.right{text-align:right}.muted{color:#64748b}.summary{display:flex;gap:18px;margin:20px 0}.box{border:1px solid #e5e7eb;padding:12px;flex:1}@media print{button{display:none}}</style></head><body>
